changeSet.sql:
ALTER TABLE rtac_holding
  ADD COLUMN IF NOT EXISTS effective_shelving_order text
    GENERATED ALWAYS AS ((rtac_holding_json->>'effectiveShelvingOrder')) STORED;
ALTER TABLE rtac_holding
  ADD COLUMN IF NOT EXISTS status_name text
    GENERATED ALWAYS AS ((rtac_holding_json->>'status')) STORED;
ALTER TABLE rtac_holding
  ADD COLUMN IF NOT EXISTS library_name text
    GENERATED ALWAYS AS ((rtac_holding_json->'library'->>'name')) STORED;
ALTER TABLE rtac_holding
  ADD COLUMN IF NOT EXISTS location_name text
    GENERATED ALWAYS AS ((rtac_holding_json->'location'->>'name')) STORED;

CREATE INDEX CONCURRENTLY IF NOT EXISTS idx_rtac_holding_default_sort_cols
ON rtac_holding (
  instance_id,
  effective_shelving_order DESC,
  status_name ASC,
  library_name ASC,
  location_name ASC
);

-- Replace the JSON-expression index with the generated-column index to reduce write overhead.
DROP INDEX CONCURRENTLY IF EXISTS idx_rtac_holding_default_sort;
